final:
module JK_latch (  
    input J,  
    input K,  
    input clk,  
    output reg Q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (J && !K)  
            Q <= 1;  
        else if (!J && K)  
            Q <= 0;  
        else if (J && K)  
            Q <= ~Q;  
        // If both J and K are low, Q remains the same  
    end  
endmodule
